-- ----------------------------------------------------------------------------
-- vw_app_users: Table: AppUsers
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_app_users WITH (security_invoker = ON) AS
SELECT
  t.app_user_id,
  calc_app_users_name(t.app_user_id) AS name,
  t.contact_name,
  t.email_address,
  t.phone_number,
  t.role,
  t.notes,
  calc_app_users_client_approvals(t.app_user_id) AS client_approvals
FROM app_users t;

-- ----------------------------------------------------------------------------
-- vw_clients: Table: Clients
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_clients WITH (security_invoker = ON) AS
SELECT
  t.client_id,
  t.name,                                                                       -- Human-readable customer name.
  t.notes,                                                                      -- Free-form notes about the customer.
  t.category,
  calc_clients_category_name(t.client_id) AS category_name,
  calc_clients_category_discount(t.client_id) AS category_discount,
  calc_clients_is_stopped(t.client_id) AS is_stopped,                           -- True when the customer's current Status is a blocking status. Lookup of Statuses.IsBlocking.
  t.status,                                                                     -- Link to the customer's current Status in the Statuses table.
  calc_clients_status_display_name(t.client_id) AS status_display_name,         -- Human-readable display name of the customer's current Status. Lookup of Statuses.DisplayName.
  calc_clients_status_description(t.client_id) AS status_description,           -- Description of the customer's current Status. Lookup of Statuses.Description.
  calc_clients_invoices(t.client_id) AS invoices,                               -- Reverse link to all Orders placed by this customer.
  calc_clients_count_of_big_invoices(t.client_id) AS count_of_big_invoices,
  t.email,                                                                      -- Primary email address for the customer.
  t.phone,                                                                      -- Primary phone number for the customer.
  t.company_name,                                                               -- Company the customer represents, if applicable.
  t.addresses,
  calc_clients_billing_address_state_tax_rate(t.client_id) AS billing_address_state_tax_rate,
  calc_clients_billing_address(t.client_id) AS billing_address,                 -- Default billing address for the customer.
  calc_clients_shipping_address(t.client_id) AS shipping_address,               -- Default shipping address for the customer.
  t.created_at,                                                                 -- Timestamp when the customer record was created.
  calc_clients_average_order_value(t.client_id) AS average_order_value,
  calc_clients_is_vip(t.client_id) AS is_vip,
  calc_clients_has_recent_invoices(t.client_id) AS has_recent_invoices,
  calc_clients_last_invoice(t.client_id) AS last_invoice,
  calc_clients_customer_since_days(t.client_id) AS customer_since_days,
  calc_clients_client_approvals(t.client_id) AS client_approvals
FROM clients t;

