-- vw_invoices: Table: Invoices
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_invoices WITH (security_invoker = ON) AS
SELECT
  t.invoice_id,
  calc_invoices_name(t.invoice_id) AS name,                                     -- Lowercase compound key combining the linked Customer and OrderNumber (e.g. 'bob-1001'). Used as the natural key for the order.
  t.invoice_number,                                                             -- Sequential or human-assigned order identifier (e.g. '1001'). Combined with Customer to form the order's natural key.
  t.client,                                                                     -- Link to the Customer who placed this order.
  calc_invoices_client_is_vip(t.invoice_id) AS client_is_vip,
  calc_invoices_client_hast_recent_invoices(t.invoice_id) AS client_hast_recent_invoices,
  calc_invoices_client_email(t.invoice_id) AS client_email,
  calc_invoices_client_phone(t.invoice_id) AS client_phone,
  calc_invoices_client_company_name(t.invoice_id) AS client_company_name,
  calc_invoices_client_category_name(t.invoice_id) AS client_category_name,
  calc_invoices_client_category_discount(t.invoice_id) AS client_category_discount,
  calc_invoices_invoice_line_items(t.invoice_id) AS invoice_line_items,         -- Reverse link to all OrderLineItems on this order.
  calc_invoices_payments(t.invoice_id) AS payments,                             -- Reverse link to all Payments applied to this order.
  t.order_date,                                                                 -- When the order was placed.
  t.order_status,                                                               -- Lifecycle state of the order.
  t.shipping_address,                                                           -- Where this specific order ships to.
  t.billing_address,                                                            -- Billing address used for this specific order.
  t.notes,                                                                      -- Free-form notes about this order.
  calc_invoices_item_count(t.invoice_id) AS item_count,
  calc_invoices_total_quantity(t.invoice_id) AS total_quantity,
  calc_invoices_sub_total(t.invoice_id) AS sub_total,
  calc_invoices_is_big_order(t.invoice_id) AS is_big_order,
  calc_invoices_tax_rate(t.invoice_id) AS tax_rate,                             -- Sales tax rate applied to this order.
  calc_invoices_tax_amount(t.invoice_id) AS tax_amount,
  calc_invoices_invoice_total(t.invoice_id) AS invoice_total,
  calc_invoices_total_paid(t.invoice_id) AS total_paid,
  calc_invoices_amount_due(t.invoice_id) AS amount_due,
  calc_invoices_is_paid_in_full(t.invoice_id) AS is_paid_in_full,
  calc_invoices_payment_count(t.invoice_id) AS payment_count,
  calc_invoices_last_payment_date(t.invoice_id) AS last_payment_date,
  calc_invoices_payment_status_label(t.invoice_id) AS payment_status_label
FROM invoices t;

-- ----------------------------------------------------------------------------
-- vw_invoice_line_items: Table: InvoiceLineItems
-- Combines base table columns with calculated/lookup/aggregation fields.
-- ----------------------------------------------------------------------------
CREATE OR REPLACE VIEW vw_invoice_line_items WITH (security_invoker = ON) AS
SELECT
  t.invoice_line_item_id,
  calc_invoice_line_items_name(t.invoice_line_item_id) AS name,                 -- Lowercase compound key combining the linked Order and LineNumber (e.g. 'bob-1001-line-1'). Used as the natural key for the line item.
  t.line_number,                                                                -- Position of this line within its parent Order (e.g. '1', '2'). Combined with Order to form the line item's natural key.
  t.invoice,                                                                    -- Link to the parent Order this line item belongs to.
  calc_invoice_line_items_client_is_vip(t.invoice_line_item_id) AS client_is_vip,
  calc_invoice_line_items_client_hast_recent_invoices(t.invoice_line_item_id) AS client_hast_recent_invoices,
  calc_invoice_line_items_invoice_number(t.invoice_line_item_id) AS invoice_number,
  calc_invoice_line_items_invoice_total(t.invoice_line_item_id) AS invoice_total,
  calc_invoice_line_items_invoice_total_paid(t.invoice_line_item_id) AS invoice_total_paid,
  t.product,                                                                    -- Link to the Product being ordered on this line.
  calc_invoice_line_items_product_sku(t.invoice_line_item_id) AS product_sku,
  calc_invoice_line_items_product_display_name(t.invoice_line_item_id) AS product_display_name,
  t.quantity,                                                                   -- Number of units ordered on this line.
  calc_invoice_line_items_unit_price(t.invoice_line_item_id) AS unit_price,     -- Price per unit captured at the time of ordering (may differ from current Product.UnitPrice).
  calc_invoice_line_items_pre_discount(t.invoice_line_item_id) AS pre_discount,
  calc_invoice_line_items_discount_percent(t.invoice_line_item_id) AS discount_percent,-- Per-line discount applied to this item.
  calc_invoice_line_items_discount_amount(t.invoice_line_item_id) AS discount_amount,
  calc_invoice_line_items_sub_total(t.invoice_line_item_id) AS sub_total,
  t.notes                                                                       -- Free-form notes about this line item.
FROM invoice_line_items t;

